import json, pathlib, re, runpy, sys; root = pathlib.Path.home() / '.codex' / 'plugins' / 'cache' / 'codex-loop-plugin' / 'codex-loop';

def _key(p):
    script = p / 'scripts' / 'codex-loop-mcp'
    if not script.is_file():
        return None
    version = p.name
    manifest = p / '.codex-plugin' / 'plugin.json'
    try:
        version = json.loads(manifest.read_text(encoding='utf-8')).get('version') or version
    except Exception:
        pass
    return (tuple(int(part) for part in re.findall(r'\d+', version)), p.stat().st_mtime)

candidates = [(key, p) for p in root.iterdir() if p.is_dir() for key in [_key(p)] if key is not None]
if not candidates:
    raise SystemExit(f'no usable codex-loop-mcp under {root}')
script = max(candidates, key=lambda item: item[0])[1] / 'scripts' / 'codex-loop-mcp'
sys.path.insert(0, str(script.parent))
runpy.run_path(str(script), run_name='__main__')
